  1→<!DOCTYPE html>
  2→<html lang="en">
  3→<head>
  4→<meta charset="UTF-8">
  5→<meta name="viewport" content="width=device-width, initial-scale=1.0">
  6→<title>Claude Usage Leaderboard</title>
  7→<style>
  8→  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&family=JetBrains+Mono:wght@400;700&display=swap');
  9→
 10→  :root {
 11→    --bg-primary: #0a0a0f;
 12→    --bg-secondary: #12121a;
 13→    --bg-card: #1a1a2e;
 14→    --bg-card-hover: #22223a;
 15→    --accent-orange: #f97316;
 16→    --accent-purple: #a855f7;
 17→    --accent-blue: #3b82f6;
 18→    --accent-green: #22c55e;
 19→    --accent-pink: #ec4899;
 20→    --accent-cyan: #06b6d4;
 21→    --text-primary: #f1f5f9;
 22→    --text-secondary: #94a3b8;
 23→    --text-dim: #475569;
 24→    --border: #1e293b;
 25→    --border-subtle: #161625;
 26→    --ny-color: #3b82f6;
 27→    --xyne-color: #a855f7;
 28→    --nc-color: #22c55e;
 29→    --hs-color: #f59e0b;
 30→    --jp-color: #e11d48;
 31→    --gold: #fbbf24;
 32→    --silver: #94a3b8;
 33→    --bronze-color: #cd7f32;
 34→  }
 35→
 36→  * { margin: 0; padding: 0; box-sizing: border-box; }
 37→
 38→  html { overflow-x: hidden; }
 39→
 40→  body {
 41→    font-family: 'Inter', sans-serif;
 42→    background: var(--bg-primary);
 43→    color: var(--text-primary);
 44→    min-height: 100vh;
 45→    overflow-x: hidden;
 46→    max-width: 100vw;
 47→    -webkit-font-smoothing: antialiased;
 48→  }
 49→
 50→  body::before {
 51→    content: '';
 52→    position: fixed;
 53→    top: 0; left: 0; right: 0; bottom: 0;
 54→    background:
 55→      radial-gradient(ellipse at 20% 50%, rgba(168, 85, 247, 0.06) 0%, transparent 50%),
 56→      radial-gradient(ellipse at 80% 20%, rgba(59, 130, 246, 0.06) 0%, transparent 50%),
 57→      radial-gradient(ellipse at 50% 80%, rgba(34, 197, 94, 0.04) 0%, transparent 50%);
 58→    z-index: 0;
 59→    animation: bgPulse 10s ease-in-out infinite alternate;
 60→  }
 61→
 62→  @keyframes bgPulse { 0% { opacity: 0.5; } 100% { opacity: 1; } }
 63→
 64→  .container { position: relative; z-index: 1; max-width: 1300px; margin: 0 auto; padding: 24px 20px; }
 65→
 66→  /* Header */
 67→  .header { text-align: center; padding: 40px 0 24px; }
 68→  .header h1 {
 69→    font-size: 2.4rem; font-weight: 900;
 70→    background: linear-gradient(135deg, var(--accent-orange), var(--accent-purple), var(--accent-blue));
 71→    -webkit-background-clip: text; background-clip: text; -webkit-text-fill-color: transparent;
 72→    letter-spacing: -0.5px; margin-bottom: 8px;
 73→  }
 74→  .header .subtitle { color: var(--text-secondary); font-size: 0.95rem; font-weight: 400; }
 75→
 76→  .live-badge {
 77→    display: inline-flex; align-items: center; gap: 6px;
 78→    background: rgba(239, 68, 68, 0.1); border: 1px solid rgba(239, 68, 68, 0.2);
 79→    color: #ef4444; padding: 4px 14px; border-radius: 20px;
 80→    font-size: 0.7rem; font-weight: 700; text-transform: uppercase; letter-spacing: 1.5px; margin-top: 12px;
 81→  }
 82→  .live-dot {
 83→    width: 6px; height: 6px; background: #ef4444; border-radius: 50%;
 84→    animation: livePulse 1.5s ease-in-out infinite;
 85→  }
 86→  @keyframes livePulse { 0%, 100% { opacity: 1; transform: scale(1); } 50% { opacity: 0.3; transform: scale(0.7); } }
 87→
 88→  /* Utilisation Gauge */
 89→  .utilisation-gauge {
 90→    background: var(--bg-card); border: 1px solid var(--border); border-radius: 16px;
 91→    padding: 20px 28px 16px; margin: 16px 0 20px; text-align: center;
 92→  }
 93→  .gauge-amounts { font-size: 1.4rem; font-weight: 800; font-family: 'JetBrains Mono', monospace; }
 94→  .gauge-utilised { color: #2DC653; }
 95→  .gauge-sep { color: rgba(255,255,255,0.3); margin: 0 4px; }
 96→  .gauge-budget { color: var(--accent-orange); }
 97→  .gauge-label { font-size: 0.65rem; font-weight: 600; color: rgba(255,255,255,0.4); text-transform: uppercase; letter-spacing: 2px; margin-left: 10px; vertical-align: middle; }
 98→  .gauge-amounts-usd { font-size: 0.75rem; color: rgba(255,255,255,0.35); margin-top: 2px; font-family: 'JetBrains Mono', monospace; }
 99→  .gauge-bar-wrap { display: flex; align-items: center; gap: 12px; margin: 12px 0 8px; }
100→  .gauge-bar-track { flex: 1; height: 18px; background: rgba(255,255,255,0.06); border-radius: 9px; overflow: visible; position: relative; }
101→  .gauge-bar-fill { height: 100%; border-radius: 9px; transition: width 0.8s ease, background 0.5s ease; min-width: 2px; position: relative; z-index: 1; }
102→  .gauge-bar-possible { position:absolute; top:0; left:0; height:100%; border-radius:9px; background:rgba(255,255,255,0.06); z-index:0; transition: width 0.8s; }
103→  .gauge-bar-marker { position: absolute; top: -3px; bottom: -3px; width: 2px; background: rgba(255,255,255,0.3); border-radius: 1px; }
104→  .gauge-pct { font-size: 1.1rem; font-weight: 800; font-family: 'JetBrains Mono', monospace; min-width: 48px; }
105→  .gauge-sub { font-size: 0.72rem; color: rgba(255,255,255,0.45); display: flex; justify-content: center; gap: 8px; flex-wrap: wrap; }
106→  .gauge-dot { opacity: 0.3; }
107→  .gauge-beyond { color: rgba(168,85,247,0.6); cursor: help; font-style: italic; }
108→
109→  /* Stats (legacy) */
110→  .stats-bar { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin: 24px 0; }
111→  .stat-card {
112→    background: var(--bg-card); border: 1px solid var(--border); border-radius: 14px;
113→    padding: 20px; text-align: center; transition: all 0.3s;
114→  }
115→  .stat-card:hover { border-color: rgba(168, 85, 247, 0.3); transform: translateY(-2px); }
116→  .stat-value { font-size: 1.6rem; font-weight: 800; font-family: 'JetBrains Mono', monospace; }
117→  .stat-label { font-size: 0.65rem; color: var(--text-secondary); text-transform: uppercase; letter-spacing: 1.5px; margin-top: 6px; font-weight: 500; }
118→  .stat-value.orange { color: var(--accent-orange); }
119→  .stat-value.purple { color: var(--accent-purple); }
120→  .stat-value.blue { color: var(--accent-blue); }
121→  .stat-value.green { color: var(--accent-green); }
122→
123→  /* Team Battle */
124→  /* Leaderboard Section at Top */
125→  .leaderboard-section { margin: 20px 0; }
126→  .lb-dual {
127→    display: grid; grid-template-columns: 1fr 1fr; gap: 16px;
128→  }
129→  .lb-section { margin-bottom: 24px; }
130→  .lb-section-title {
131→    font-size: 0.75rem; font-weight: 700; color: var(--text-dim);
132→    text-transform: uppercase; letter-spacing: 2px; margin-bottom: 10px;
133→    display: flex; align-items: center; gap: 8px;
134→  }
135→  .lb-section-title::before {
136→    content: ''; flex: 1; height: 1px; background: var(--border);
137→  }
138→  .lb-section-title::after {
139→    content: ''; flex: 1; height: 1px; background: var(--border);
140→  }
141→
142→  /* Team Battle Mini (compact for top) */
143→  .team-battle-mini {
144→    background: var(--bg-card); border: 1px solid var(--border); border-radius: 12px;
145→    padding: 12px 16px; margin-bottom: 16px;
146→  }
147→  .team-mini-row {
148→    display: flex; justify-content: space-around; gap: 8px;
149→  }
150→  .team-mini-ny, .team-mini-nc, .team-mini-xyne, .team-mini-hs, .team-mini-jp {
151→    display: flex; flex-direction: column; align-items: center; gap: 2px;
152→    flex: 1; padding: 6px 4px; border-radius: 8px;
153→    background: var(--bg-secondary);
154→  }
155→  .team-mini-name {
156→    font-size: 0.6rem; font-weight: 700; text-transform: uppercase; letter-spacing: 1px;
157→  }
158→  .team-mini-ny .team-mini-name { color: var(--ny-color); }
159→  .team-mini-nc .team-mini-name { color: var(--nc-color); }
160→  .team-mini-xyne .team-mini-name { color: var(--xyne-color); }
161→  .team-mini-hs .team-mini-name { color: var(--hs-color); }
162→  .team-mini-jp .team-mini-name { color: var(--jp-color); }
163→  .team-mini-pct {
164→    font-size: 0.9rem; font-weight: 800; font-family: 'JetBrains Mono', monospace;
165→    color: var(--text-primary);
166→  }
167→
168→  .team-battle {
169→    background: var(--bg-card); border: 1px solid var(--border); border-radius: 16px;
170→    padding: 28px; margin: 20px 0; position: relative; overflow: hidden;
171→  }
172→  .team-battle::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 2px; background: linear-gradient(90deg, var(--ny-color), var(--nc-color), var(--xyne-color), var(--hs-color), var(--jp-color)); }
173→  .team-battle h2 { text-align: center; font-size: 0.8rem; font-weight: 700; margin-bottom: 20px; color: var(--text-dim); text-transform: uppercase; letter-spacing: 3px; }
174→  .team-vs { display: flex; align-items: center; justify-content: center; gap: 20px; }
175→  .team-side { flex: 1; text-align: center; }
176→  .team-name { font-size: 1.1rem; font-weight: 800; margin-bottom: 4px; letter-spacing: 1px; }
177→  .team-name.ny { color: var(--ny-color); }
178→  .team-name.xyne { color: var(--xyne-color); }
179→  .team-name.nc { color: var(--nc-color); }
180→  .team-name.hs { color: var(--hs-color); }
181→  .team-name.jp { color: var(--jp-color); }
182→  .team-pct { font-size: 2rem; font-weight: 900; font-family: 'JetBrains Mono', monospace; }
183→  .team-details { font-size: 0.75rem; color: var(--text-dim); margin-top: 4px; }
184→  .team-bars { display: flex; flex-direction: column; gap: 6px; margin-top: 20px; }
185→  .team-bar-row { display: flex; align-items: center; gap: 10px; }
186→  .team-bar-label { font-size: 0.65rem; font-weight: 700; min-width: 40px; width: 40px; text-align: right; letter-spacing: 0.5px; }
187→  .team-bar-track { flex: 1; height: 6px; background: var(--bg-primary); border-radius: 3px; overflow: hidden; }
188→  .team-bar-fill { height: 100%; border-radius: 3px; transition: width 1s ease; }
189→  .team-bar-fill.ny { background: linear-gradient(90deg, var(--ny-color), #60a5fa); }
190→  .team-bar-fill.xyne { background: linear-gradient(90deg, #c084fc, var(--xyne-color)); }
191→  .team-bar-fill.nc { background: linear-gradient(90deg, var(--nc-color), #4ade80); }
192→  .team-bar-fill.hs { background: linear-gradient(90deg, var(--hs-color), #fbbf24); }
193→  .team-bar-fill.jp { background: linear-gradient(90deg, var(--jp-color), #fb7185); }
194→  .team-bar-value { font-size: 0.7rem; font-family: 'JetBrains Mono', monospace; color: var(--text-dim); width: 40px; }
195→
196→  /* Setup Section */
197→  .setup-section {
198→    background: var(--bg-card); border: 1px solid var(--border); border-radius: 14px;
199→    margin: 20px 0; overflow: hidden;
200→  }
201→  .setup-header {
202→    display: flex; align-items: center; justify-content: space-between;
203→    padding: 18px 24px; cursor: pointer; user-select: none; transition: background 0.2s;
204→  }
205→  .setup-header:hover { background: var(--bg-card-hover); }
206→  .setup-header h3 { font-size: 0.9rem; font-weight: 700; display: flex; align-items: center; gap: 10px; }
207→  .setup-header .badge {
208→    font-size: 0.6rem; font-weight: 700; padding: 3px 8px; border-radius: 4px;
209→    background: rgba(34, 197, 94, 0.15); color: var(--accent-green); border: 1px solid rgba(34, 197, 94, 0.3);
210→    text-transform: uppercase; letter-spacing: 1px;
211→  }
212→  .setup-chevron { color: var(--text-dim); transition: transform 0.3s; font-size: 0.8rem; }
213→  .setup-section.open .setup-chevron { transform: rotate(180deg); }
214→  .setup-body { max-height: 0; overflow: hidden; transition: max-height 0.4s ease; }
215→  .setup-section.open .setup-body { max-height: 600px; }
216→  .setup-body-inner { padding: 0 24px 24px; }
217→  .setup-method {
218→    padding: 16px; border-radius: 10px; border: 1px solid var(--border-subtle);
219→    background: var(--bg-secondary); margin-bottom: 12px;
220→  }
221→  .setup-method:last-child { margin-bottom: 0; }
222→  .setup-method h4 { font-size: 0.8rem; font-weight: 700; margin-bottom: 6px; display: flex; align-items: center; gap: 8px; }
223→  .setup-method h4 .tag {
224→    font-size: 0.55rem; font-weight: 700; padding: 2px 6px; border-radius: 3px;
225→    background: rgba(168, 85, 247, 0.15); color: var(--accent-purple); text-transform: uppercase; letter-spacing: 0.5px;
226→  }
227→  .setup-method p { font-size: 0.78rem; color: var(--text-secondary); line-height: 1.7; }
228→  .setup-method ol { font-size: 0.78rem; color: var(--text-secondary); line-height: 2; padding-left: 20px; margin-top: 8px; }
229→  .setup-method ol code {
230→    background: var(--bg-primary); padding: 2px 6px; border-radius: 4px;
231→    font-family: 'JetBrains Mono', monospace; font-size: 0.72rem;
232→  }
233→  .setup-method .download-btn {
234→    display: inline-block; padding: 8px 18px; margin-top: 10px;
235→    background: linear-gradient(135deg, var(--accent-purple), var(--accent-blue));
236→    color: white; font-size: 0.78rem; font-weight: 700; border-radius: 8px;
237→    text-decoration: none; transition: all 0.2s;
238→  }
239→  .setup-method .download-btn:hover { transform: translateY(-1px); box-shadow: 0 4px 15px rgba(168, 85, 247, 0.3); }
240→  .setup-method .bookmarklet-link {
241→    display: inline-block; padding: 6px 14px; margin-top: 8px;
242→    background: var(--bg-primary); border: 1px solid var(--border);
243→    color: var(--text-secondary); font-size: 0.75rem; font-weight: 600; border-radius: 6px;
244→    text-decoration: none; cursor: grab;
245→  }
246→  .setup-note {
247→    display: flex; align-items: flex-start; gap: 8px; margin-top: 12px; padding: 10px 14px;
248→    background: rgba(251, 191, 36, 0.06); border: 1px solid rgba(251, 191, 36, 0.15);
249→    border-radius: 8px; font-size: 0.72rem; color: var(--text-secondary); line-height: 1.5;
250→  }
251→  .setup-note .note-icon { flex-shrink: 0; font-size: 0.85rem; }
252→
253→  /* Actions */
254→  .actions { display: flex; gap: 8px; margin: 24px 0 16px; flex-wrap: wrap; align-items: center; }
255→  .btn {
256→    padding: 9px 18px; border: 1px solid var(--border); border-radius: 8px; background: var(--bg-card);
257→    color: var(--text-primary); font-family: 'Inter', sans-serif; font-size: 0.8rem;
258→    font-weight: 600; cursor: pointer; transition: all 0.2s; display: inline-flex; align-items: center; gap: 6px;
259→    white-space: nowrap;
260→  }
261→  .btn:hover { transform: translateY(-1px); border-color: var(--accent-purple); }
262→  .btn.primary { background: linear-gradient(135deg, var(--accent-purple), var(--accent-blue)); border: none; }
263→  .btn.primary:hover { box-shadow: 0 4px 20px rgba(168, 85, 247, 0.3); }
264→  .btn.danger { border-color: rgba(239, 68, 68, 0.2); color: rgba(239, 68, 68, 0.7); font-size: 0.75rem; }
265→  .btn.danger:hover { background: rgba(239, 68, 68, 0.1); }
266→  .btn.secondary { background: transparent; color: var(--text-secondary); font-size: 0.75rem; }
267→
268→  /* Tabs */
269→  .board-tabs {
270→    display: flex; gap: 0; margin: 20px 0 8px; justify-content: center;
271→  }
272→  .board-tab {
273→    padding: 10px 28px; border: 1px solid var(--border); background: var(--bg-secondary);
274→    color: var(--text-secondary); font-family: 'Inter', sans-serif; font-size: 0.8rem;
275→    font-weight: 700; cursor: pointer; transition: all 0.2s; text-transform: uppercase; letter-spacing: 1px;
276→  }
277→  .board-tab:first-child { border-radius: 10px 0 0 10px; }
278→  .board-tab:last-child { border-radius: 0 10px 10px 0; }
279→  .board-tab.active {
280→    background: linear-gradient(135deg, var(--accent-purple), var(--accent-blue));
281→    border-color: var(--accent-purple); color: white;
282→  }
283→  .board-tab:hover:not(.active) { border-color: var(--accent-purple); color: var(--text-primary); }
284→
285→  .tabs {
286→    display: flex; gap: 2px; margin: 8px 0 16px; background: var(--bg-secondary);
287→    padding: 3px; border-radius: 10px; border: 1px solid var(--border);
288→  }
289→  .tab {
290→    flex: 1; padding: 8px 14px; border: none; background: transparent; color: var(--text-dim);
291→    font-family: 'Inter', sans-serif; font-size: 0.78rem; font-weight: 600; cursor: pointer;
292→    border-radius: 7px; transition: all 0.2s;
293→  }
294→  .tab:hover { color: var(--text-secondary); }
295→  .tab.active { background: var(--bg-card); color: var(--text-primary); box-shadow: 0 2px 8px rgba(0,0,0,0.3); }
296→
297→  /* Main Tabs */
298→  .main-tabs {
299→    display: flex; gap: 2px; margin: 0 0 20px; background: var(--bg-secondary);
300→    padding: 3px; border-radius: 12px; border: 1px solid var(--border);

300→    padding: 3px; border-radius: 12px; border: 1px solid var(--border);
301→  }
302→  .main-tab {
303→    flex: 1; padding: 10px 18px; border: none; background: transparent; color: var(--text-dim);
304→    font-family: 'Inter', sans-serif; font-size: 0.85rem; font-weight: 700; cursor: pointer;
305→    border-radius: 9px; transition: all 0.2s; text-transform: uppercase; letter-spacing: 1px;
306→  }
307→  .main-tab:hover { color: var(--text-secondary); }
308→  .main-tab.active { background: linear-gradient(135deg, var(--accent-purple), var(--accent-blue)); color: white; box-shadow: 0 2px 12px rgba(168, 85, 247, 0.3); }
309→
310→  /* Leaderboard */
311→  .leaderboard { display: flex; flex-direction: column; gap: 6px; }
312→  .lb-row {
313→    display: grid; grid-template-columns: 32px 1fr 60px 60px;
314→    align-items: center; background: var(--bg-card); border: 1px solid var(--border);
315→    border-radius: 12px; padding: 10px 14px; transition: all 0.3s; cursor: pointer;
316→    animation: slideIn 0.4s ease backwards; gap: 6px;
317→  }
318→  .lb-row .lb-plans { display: none; }
319→  .lb-row .lb-usage-bar { display: none; }
320→  .lb-row:hover { border-color: rgba(168, 85, 247, 0.3); background: var(--bg-card-hover); }
321→  @keyframes slideIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
322→  .lb-row.rank-1 { border-color: rgba(251, 191, 36, 0.3); background: rgba(251, 191, 36, 0.04); }
323→  .lb-row.rank-2 { border-color: rgba(148, 163, 184, 0.2); background: rgba(148, 163, 184, 0.02); }
324→  .lb-row.rank-3 { border-color: rgba(205, 127, 50, 0.2); background: rgba(205, 127, 50, 0.02); }
325→
326→  .lb-position { font-size: 1.1rem; font-weight: 800; font-family: 'JetBrains Mono', monospace; }
327→  .lb-position.p1 { color: var(--gold); }
328→  .lb-position.p2 { color: var(--silver); }
329→  .lb-position.p3 { color: var(--bronze-color); }
330→  .lb-position.px { color: var(--text-dim); }
331→
332→  .lb-user-info { display: flex; flex-direction: column; gap: 3px; min-width: 0; }
333→  .lb-name { font-weight: 700; font-size: 0.95rem; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
334→  .lb-meta { display: flex; gap: 6px; align-items: center; flex-wrap: wrap; }
335→  .lb-team-tag {
336→    font-size: 0.6rem; font-weight: 700; padding: 2px 7px; border-radius: 4px;
337→    text-transform: uppercase; letter-spacing: 0.5px;
338→  }
339→  .lb-team-tag.ny { background: rgba(59, 130, 246, 0.12); color: var(--ny-color); border: 1px solid rgba(59, 130, 246, 0.25); }
340→  .lb-team-tag.xyne { background: rgba(168, 85, 247, 0.12); color: var(--xyne-color); border: 1px solid rgba(168, 85, 247, 0.25); }
341→  .lb-team-tag.nc { background: rgba(34, 197, 94, 0.12); color: var(--nc-color); border: 1px solid rgba(34, 197, 94, 0.25); }
342→  .lb-team-tag.hs { background: rgba(245, 158, 11, 0.12); color: var(--hs-color); border: 1px solid rgba(245, 158, 11, 0.25); }
343→  .lb-team-tag.jp { background: rgba(225, 29, 72, 0.12); color: var(--jp-color); border: 1px solid rgba(225, 29, 72, 0.25); }
344→  .lb-plan-tag {
345→    font-size: 0.55rem; font-weight: 700; padding: 1px 5px; border-radius: 3px;
346→    text-transform: uppercase; letter-spacing: 0.5px;
347→  }
348→  .lb-plan-tag.max5 { background: rgba(99, 102, 241, 0.15); color: #818cf8; border: 1px solid rgba(99, 102, 241, 0.3); }
349→  .lb-plan-tag.max20 { background: rgba(245, 158, 11, 0.15); color: #fbbf24; border: 1px solid rgba(245, 158, 11, 0.3); }
350→  .lb-outdated-tag {
351→    font-size: 0.5rem; font-weight: 600; padding: 1px 5px; border-radius: 3px;
352→    background: rgba(239, 68, 68, 0.1); color: #f87171; border: 1px solid rgba(239, 68, 68, 0.2);
353→    cursor: help;
