1147→  async function apiFetch(path, options = {}, retries = 2) {
1148→    for (let attempt = 0; attempt <= retries; attempt++) {
1149→      try {
1150→        const res = await fetch(API_BASE + path, {
1151→          headers: { 'Content-Type': 'application/json' },
1152→          ...options,
1153→        });
1154→        const contentType = res.headers.get('content-type') || '';
1155→        if (!contentType.includes('application/json')) {
1156→          throw new Error('Non-JSON response (status ' + res.status + ')');
1157→        }
1158→        return await res.json();
1159→      } catch (e) {
1160→        if (attempt < retries) {
1161→          await new Promise(r => setTimeout(r, 1000 * (attempt + 1)));
1162→          continue;
1163→        }
1164→        throw e;
1165→      }
1166→    }
1167→  }
