1194→  // SPARKLINE RENDERER (SVG)
1195→  // ============================================================
1196→  function renderSparkline(data, color = '#a855f7', w = 72, h = 20) {
1197→    if (!data || data.length < 2) {
1198→      return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}"><line x1="0" y1="${h/2}" x2="${w}" y2="${h/2}" stroke="#1e293b" stroke-width="1"/></svg>`;
1199→    }

1200→    const max = Math.max(...data, 1);
1201→    const min = Math.min(...data, 0);
1202→    const range = max - min || 1;
1203→    const points = data.map((v, i) => {
1204→      const x = (i / (data.length - 1)) * (w - 2) + 1;
1205→      const y = h - 2 - ((v - min) / range) * (h - 4);
1206→      return `${x.toFixed(1)},${y.toFixed(1)}`;
1207→    }).join(' ');
1208→    const last = data[data.length - 1];
1209→    const lastX = w - 1;
1210→    const lastY = h - 2 - ((last - min) / range) * (h - 4);
1211→    // Gradient fill area
1212→    const firstPoint = points.split(' ')[0];
1213→    const areaPoints = `${firstPoint.split(',')[0]},${h} ${points} ${lastX},${h}`;
1214→    return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">
1215→      <defs><linearGradient id="sg_${color.replace('#','')}" x1="0" y1="0" x2="0" y2="1">
1216→        <stop offset="0%" stop-color="${color}" stop-opacity="0.3"/>
1217→        <stop offset="100%" stop-color="${color}" stop-opacity="0"/>
1218→      </linearGradient></defs>
1219→      <polygon points="${areaPoints}" fill="url(#sg_${color.replace('#','')})" />
1220→      <polyline points="${points}" fill="none" stroke="${color}" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
1221→      <circle cx="${lastX.toFixed(1)}" cy="${lastY.toFixed(1)}" r="2" fill="${color}"/>
1222→    </svg>`;
1223→  }
