2262→  // Per-user countdown from actual scraped reset timestamps
2263→  // Session: if expired, roll forward in 5-hour increments to find next reset
2264→  // Weekly: if expired, roll forward in 7-day increments
2265→  function formatCountdown(isoTimestamp, type = 'session') {
2266→    if (!isoTimestamp) return null;
2267→    let resetTime = new Date(isoTimestamp).getTime();
2268→    const now = Date.now();
2269→    if (resetTime <= now) {
2270→      const interval = type === 'weekly' ? 7 * 86400000 : 5 * 3600000;
2271→      // Roll forward to next cycle
2272→      const elapsed = now - resetTime;
2273→      const cycles = Math.floor(elapsed / interval) + 1;
2274→      resetTime += cycles * interval;
2275→    }
2276→    const diff = resetTime - now;
2277→    const d = Math.floor(diff / 86400000);
2278→    const h = Math.floor((diff % 86400000) / 3600000);
2279→    const m = Math.floor((diff % 3600000) / 60000);
2280→    const s = Math.floor((diff % 60000) / 1000);
2281→    if (d > 0) return { label: `${d}d ${h}h ${m}m` };
2282→    if (h > 0) return { label: `${h}h ${m}m ${s}s` };
2283→    return { label: `${m}m ${s}s` };
2284→  }
